import React, { useState, useEffect } from 'react';
import { NotesMap, AppSettings } from './types';
import { getTodayKey, getPreviousDays, formatDateFr } from './utils/dateUtils';
import { HistoryCard } from './components/HistoryCard';

const STORAGE_KEY_NOTES = 'standup_memo_notes';
const STORAGE_KEY_SETTINGS = 'standup_memo_settings';

const App: React.FC = () => {
  const [notes, setNotes] = useState<NotesMap>({});
  const [settings, setSettings] = useState<AppSettings>({ windowSize: 3 });
  const [todayText, setTodayText] = useState('');
  const [copied, setCopied] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    const savedNotes = localStorage.getItem(STORAGE_KEY_NOTES);
    const savedSettings = localStorage.getItem(STORAGE_KEY_SETTINGS);

    if (savedNotes) {
      const parsedNotes = JSON.parse(savedNotes);
      setNotes(parsedNotes);
      const today = getTodayKey();
      if (parsedNotes[today]) {
        setTodayText(parsedNotes[today]);
      }
    }

    if (savedSettings) {
      setSettings(JSON.parse(savedSettings));
    }
  }, []);

  const saveNotes = (updatedNotes: NotesMap) => {
    setIsSaving(true);
    localStorage.setItem(STORAGE_KEY_NOTES, JSON.stringify(updatedNotes));
    setTimeout(() => setIsSaving(false), 800);
  };

  const handleTodayChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value;
    setTodayText(val);
    const today = getTodayKey();
    const updatedNotes = { ...notes, [today]: val };
    setNotes(updatedNotes);
    saveNotes(updatedNotes);
  };

  const handleHistoryChange = (date: string, value: string) => {
    const updatedNotes = { ...notes, [date]: value };
    setNotes(updatedNotes);
    saveNotes(updatedNotes);
  };

  const updateWindowSize = (n: number) => {
    const newSettings = { ...settings, windowSize: n };
    setSettings(newSettings);
    localStorage.setItem(STORAGE_KEY_SETTINGS, JSON.stringify(newSettings));
  };

  const copyPreviousToClipboard = () => {
    const prevDays = getPreviousDays(settings.windowSize);
    const summary = prevDays
      .map(d => {
        const content = notes[d] || 'Pas de notes';
        return `[${formatDateFr(d)}]\n${content}`;
      })
      .join('\n\n');

    navigator.clipboard.writeText(summary).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const historyDates = getPreviousDays(settings.windowSize);

  return (
    <div className="min-h-screen bg-[#fafafa] text-slate-900 selection:bg-slate-200">
      {/* Header */}
      <header className="sticky top-0 z-30 w-full border-b border-slate-200 bg-white/80 backdrop-blur-md">
        <div className="max-w-6xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="flex h-9 w-9 items-center justify-center rounded-lg bg-slate-900 text-white shadow-lg shadow-slate-200">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
            </div>
            <span className="font-bold text-lg tracking-tight">Standup Memo</span>
          </div>

          <div className="flex items-center gap-6">
            <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full bg-slate-100 transition-all duration-500 ${isSaving ? 'opacity-100 scale-100' : 'opacity-0 scale-95'}`}>
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
              <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">Enregistré</span>
            </div>

            <div className="flex items-center gap-2">
              <select 
                value={settings.windowSize} 
                onChange={(e) => updateWindowSize(parseInt(e.target.value))}
                className="appearance-none bg-white border border-slate-200 text-slate-700 text-xs font-semibold rounded-md hover:border-slate-300 focus:ring-2 focus:ring-slate-900 focus:outline-none block px-3 py-1.5 transition-all cursor-pointer"
              >
                {[1, 2, 3, 5, 7, 10].map(n => (
                  <option key={n} value={n}>{n} jours d'historique</option>
                ))}
              </select>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6 py-10">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">

          {/* Main Workspace */}
          <div className="lg:col-span-7 space-y-6">
            <div className="flex items-end justify-between px-1">
              <div>
                <h2 className="text-2xl font-bold text-slate-900">Aujourd'hui</h2>
                <p className="text-sm text-slate-500 font-medium">{formatDateFr(getTodayKey())}</p>
              </div>
            </div>

            <div className="relative group">
              <div className="absolute -inset-0.5 bg-gradient-to-r from-slate-200 to-slate-100 rounded-[22px] blur opacity-25 group-focus-within:opacity-50 transition duration-1000"></div>
