                )}
                {copied ? 'Copié' : 'Tout Copier'}
              </button>
            </div>

            <div className="space-y-4 overflow-y-auto max-h-[calc(100vh-220px)] pr-2 custom-scrollbar">
              {historyDates.length > 0 ? (
                historyDates.map(date => (
